// ─── Types ───────────────────────────────────────────────────────────────────

export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, unknown>[];
  headers: string[];
  errors: CSVError[];
  filter: (predicate: (row: Record<string, unknown>) => boolean) => Record<string, unknown>[];
  sum: (column: string) => number;
  average: (column: string) => number;
  count: () => number;
  groupBy: (column: string) => Map<unknown, Record<string, unknown>[]>;
}

// ─── Field-level parser (handles quoting & escaping) ─────────────────────────

function parseFields(line: string, delimiter: string, quote: string): string[] {
  const fields: string[] = [];
  let i = 0;
  const len = line.length;

  while (i <= len) {
    if (i === len) {
      // trailing delimiter produced an empty final field
      fields.push("");
      break;
    }

    if (line[i] === quote) {
      // ── quoted field ──
      let value = "";
      i++; // skip opening quote
      while (i < len) {
        if (line[i] === quote) {
          if (i + 1 < len && line[i + 1] === quote) {
            // escaped quote ("")
            value += quote;
            i += 2;
          } else {
            // closing quote
            i++; // skip closing quote
            break;
          }
        } else {
          value += line[i];
          i++;
        }
      }
      fields.push(value);
      // skip delimiter (or we're at end of line)
      if (i < len && line[i] === delimiter) {
        i++;
        // if delimiter is the last char, there's one more empty field
        if (i === len) {
          fields.push("");
          break;
        }
      } else {
        // reached end or unexpected char – just move on
        break;
      }
    } else {
      // ── unquoted field ──
      const next = line.indexOf(delimiter, i);
      if (next === -1) {
        fields.push(line.substring(i));
        break;
      } else {
        fields.push(line.substring(i, next));
        i = next + 1;
        // trailing delimiter
        if (i === len) {
          fields.push("");
          break;
        }
      }
    }
  }

  return fields;
}

// ─── Splitting input into lines respecting quoted fields ─────────────────────

function splitLines(input: string, lineSeparator: string, quote: string): string[] {
  const lines: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;
  const len = input.length;
  const sepLen = lineSeparator.length;

  while (i < len) {
    if (input[i] === quote) {
      inQuotes = !inQuotes;
      current += input[i];
      i++;
    } else if (!inQuotes && input.substring(i, i + sepLen) === lineSeparator) {
      lines.push(current);
      current = "";
      i += sepLen;
    } else {
      current += input[i];
      i++;
    }
  }

  // push last segment (ignore if completely empty trailing line)
  if (current.length > 0) {
    lines.push(current);
  }

  return lines;
}

// ─── Type coercion ───────────────────────────────────────────────────────────

function coerce(value: string): unknown {
  // null / empty
  if (value === "" || value === "null" || value === "NULL") {
    return null;
  }

  // boolean (case-insensitive)
  const lower = value.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;

  // number – must be the *entire* string, no leftover chars
  if (/^-?\d+$/.test(value)) {
    return parseInt(value, 10);
  }
  if (/^-?\d+\.\d+$/.test(value)) {
    return parseFloat(value);
  }

  return value;
}

// ─── Main entry point ────────────────────────────────────────────────────────

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator ?? "\n";

  const errors: CSVError[] = [];

  // Handle empty / whitespace-only input
  const trimmed = input.trim();
  if (trimmed.length === 0) {
    return buildResult([], [], errors);
  }

  const lines = splitLines(trimmed, lineSeparator, quote);

  if (lines.length === 0) {
    return buildResult([], [], errors);
  }

  // First line → headers
  const headers = parseFields(lines[0], delimiter, quote).map((h) => h.trim());

  const rows: Record<string, unknown>[] = [];

  for (let idx = 1; idx < lines.length; idx++) {
    const line = lines[idx];
    // skip blank lines
    if (line.trim() === "") continue;

    const fields = parseFields(line, delimiter, quote);

    if (fields.length !== headers.length) {
      errors.push({
        row: idx + 1, // 1-based, header is row 1
        message: `Expected ${headers.length} fields but got ${fields.length}`,
      });
      continue; // skip malformed row
    }

    const row: Record<string, unknown> = {};
    for (let c = 0; c < headers.length; c++) {
      row[headers[c]] = coerce(fields[c]);
    }
    rows.push(row);
  }

  return buildResult(rows, headers, errors);
}

// ─── Build the result object with helper methods ─────────────────────────────

function buildResult(
  rows: Record<string, unknown>[],
  headers: string[],
  errors: CSVError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, unknown>) => boolean): Record<string, unknown>[] {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
        }
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, Record<string, unknown>[]> {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = row[column];
        let group = map.get(key);
        if (!group) {
          group = [];
          map.set(key, group);
        }
        group.push(row);
      }
      return map;
    },
  };
}

import { parseCSV } from "./csv-parser";

// ─── tiny test harness ───────────────────────────────────────────────────────

let passed = 0;
let failed = 0;
const failures: string[] = [];

function assert(condition: boolean, message: string): void {
  if (!condition) {
    failed++;
    failures.push(message);
    console.error(`  ✗ ${message}`);
  } else {
    passed++;
    console.log(`  ✓ ${message}`);
  }
}

function assertEqual(actual: unknown, expected: unknown, label: string): void {
  const a = JSON.stringify(actual);
  const e = JSON.stringify(expected);
  if (a !== e) {
    failed++;
    const msg = `${label}\n      expected: ${e}\n      actual:   ${a}`;
    failures.push(msg);
    console.error(`  ✗ ${msg}`);
  } else {
    passed++;
    console.log(`  ✓ ${label}`);
  }
}

function section(name: string): void {
  console.log(`\n── ${name} ──`);
}

// ─── Tests ───────────────────────────────────────────────────────────────────

// 1. Basic parsing
section("Basic parsing");
{
  const csv = `name,age,city
Alice,30,New York
Bob,25,London`;
  const result = parseCSV(csv);
  assertEqual(result.headers, ["name", "age", "city"], "headers parsed correctly");
  assertEqual(result.rows.length, 2, "two data rows");
  assertEqual(result.rows[0]["name"], "Alice", "first row name");
  assertEqual(result.rows[0]["age"], 30, "first row age (number)");
  assertEqual(result.rows[0]["city"], "New York", "first row city");
  assertEqual(result.rows[1]["name"], "Bob", "second row name");
  assertEqual(result.errors.length, 0, "no errors");
}

// 2. Quoted fields with commas
section("Quoted fields with commas");
{
  const csv = `name,address,age
"Smith, John","123 Main St, Apt 4",42
"Doe, Jane","456 Oak Ave",31`;
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["name"], "Smith, John", "quoted name with comma");
  assertEqual(result.rows[0]["address"], "123 Main St, Apt 4", "quoted address with comma");
  assertEqual(result.rows[0]["age"], 42, "age after quoted fields");
  assertEqual(result.rows[1]["name"], "Doe, Jane", "second quoted name");
  assertEqual(result.errors.length, 0, "no errors with quoted fields");
}

// 3. Escaped quotes
section("Escaped quotes");
{
  const csv = `title,description
"Hello ""World""","She said ""hi""!"
"Normal","No quotes here"`;
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["title"], 'Hello "World"', "escaped quotes in title");
  assertEqual(result.rows[0]["description"], 'She said "hi"!', "escaped quotes in description");
  assertEqual(result.rows[1]["title"], "Normal", "normal field after escaped");
  assertEqual(result.errors.length, 0, "no errors with escaped quotes");
}

// 4. Custom delimiters
section("Custom delimiters");
{
  // tab delimiter
  const tsv = `name\tage\tcity\nAlice\t30\tParis`;
  const result = parseCSV(tsv, { delimiter: "\t" });
  assertEqual(result.headers, ["name", "age", "city"], "tab-delimited headers");
  assertEqual(result.rows[0]["name"], "Alice", "tab-delimited name");
  assertEqual(result.rows[0]["age"], 30, "tab-delimited age");
}
{
  // semicolon delimiter
  const csv = `name;age;city\nAlice;30;Berlin`;
  const result = parseCSV(csv, { delimiter: ";" });
  assertEqual(result.rows[0]["city"], "Berlin", "semicolon-delimited city");
}
{
  // custom quote char
  const csv = `name,bio\n'Alice','She said ''hello'''`;
  const result = parseCSV(csv, { quote: "'" });
  assertEqual(result.rows[0]["name"], "Alice", "single-quote wrapped name");
  assertEqual(result.rows[0]["bio"], "She said 'hello'", "escaped single quotes");
}
{
  // custom line separator
  const csv = `name,age|Alice,30|Bob,25`;
  const result = parseCSV(csv, { lineSeparator: "|" });
  assertEqual(result.rows.length, 2, "pipe line separator: two rows");
  assertEqual(result.rows[0]["name"], "Alice", "pipe line separator: first name");
  assertEqual(result.rows[1]["name"], "Bob", "pipe line separator: second name");
}

// 5. Type coercion
section("Type coercion");
{
  const csv = `a,b,c,d,e,f,g,h,i
42,3.14,true,false,null,NULL,,hello,-7`;
  const result = parseCSV(csv);
  const r = result.rows[0];
  assertEqual(r["a"], 42, "integer coercion");
  assertEqual(typeof r["a"], "number", "integer is number type");
  assertEqual(r["b"], 3.14, "float coercion");
  assertEqual(typeof r["b"], "number", "float is number type");
  assertEqual(r["c"], true, "boolean true coercion");
  assertEqual(r["d"], false, "boolean false coercion");
  assertEqual(r["e"], null, "null coercion (lowercase)");
  assertEqual(r["f"], null, "NULL coercion (uppercase)");
  assertEqual(r["g"], null, "empty string → null");
  assertEqual(r["h"], "hello", "string stays string");
  assertEqual(r["i"], -7, "negative integer coercion");
}
{
  // case-insensitive booleans
  const csv = `v\nTRUE\nTrue\nFALSE\nFalse`;
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["v"], true, "TRUE → true");
  assertEqual(result.rows[1]["v"], true, "True → true");
  assertEqual(result.rows[2]["v"], false, "FALSE → false");
  assertEqual(result.rows[3]["v"], false, "False → false");
}

// 6. Malformed row error collection
section("Malformed row error collection");
{
  const csv = `name,age,city
Alice,30,NYC
Bob,25
Charlie,40,LA,extra
Diana,22,SF`;
  const result = parseCSV(csv);
  assertEqual(result.rows.length, 2, "only valid rows kept");
  assertEqual(result.rows[0]["name"], "Alice", "first valid row");
  assertEqual(result.rows[1]["name"], "Diana", "second valid row");
  assertEqual(result.errors.length, 2, "two errors collected");
  assertEqual(result.errors[0].row, 3, "error on row 3 (Bob)");
  assert(result.errors[0].message.includes("2"), "Bob row error mentions field count");
  assertEqual(result.errors[1].row, 4, "error on row 4 (Charlie)");
  assert(result.errors[1].message.includes("4"), "Charlie row error mentions field count");
}

// 7. Filter
section("Filter functionality");
{
  const csv = `name,age,active
Alice,30,true
Bob,17,true
Charlie,25,false
Diana,40,true`;
  const result = parseCSV(csv);

  const adults = result.filter((r) => (r["age"] as number) >= 18);
  assertEqual(adults.length, 3, "filter: 3 adults");
  assertEqual(adults[0]["name"], "Alice", "filter: first adult");

  const active = result.filter((r) => r["active"] === true);
  assertEqual(active.length, 3, "filter: 3 active");

  const none = result.filter(() => false);
  assertEqual(none.length, 0, "filter: empty result");
}

// 8. Aggregation methods
section("Aggregation: sum");
{
  const csv = `item,price,qty
Apple,1.5,10
Banana,0.75,20
Cherry,2.0,5`;
  const result = parseCSV(csv);
  assertEqual(result.sum("price"), 4.25, "sum of prices");
  assertEqual(result.sum("qty"), 35, "sum of quantities");
  assertEqual(result.sum("item"), 0, "sum of non-numeric column = 0");
}

section("Aggregation: average");
{
  const csv = `name,score
Alice,80
Bob,90
Charlie,100`;
  const result = parseCSV(csv);
  assertEqual(result.average("score"), 90, "average score");
  assertEqual(result.average("name"), 0, "average of non-numeric = 0");
}

section("Aggregation: count");
{
  const csv = `a\n1\n2\n3\n4\n5`;
  const result = parseCSV(csv);
  assertEqual(result.count(), 5, "count = 5");
}
{
  const result = parseCSV("");
  assertEqual(result.count(), 0, "count of empty = 0");
}

section("Aggregation: groupBy");
{
  const csv = `name,dept,salary
Alice,Engineering,100
Bob,Sales,80
Charlie,Engineering,120
Diana,Sales,90
Eve,Engineering,110`;
  const result = parseCSV(csv);
  const groups = result.groupBy("dept");

  assertEqual(groups.size, 2, "groupBy: 2 departments");
  assertEqual(groups.get("Engineering")!.length, 3, "groupBy: 3 in Engineering");
  assertEqual(groups.get("Sales")!.length, 2, "groupBy: 2 in Sales");
  assertEqual(groups.get("Engineering")![0]["name"], "Alice", "groupBy: first engineer");
}
{
  // groupBy with null values
  const csv = `name,team\nAlice,A\nBob,\nCharlie,A\nDiana,`;
  const result = parseCSV(csv);
  const groups = result.groupBy("team");
  assertEqual(groups.get("A")!.length, 2, "groupBy null: 2 in team A");
  assertEqual(groups.get(null as unknown)!.length, 2, "groupBy null: 2 with null team");
}

// 9. Edge cases
section("Edge case: empty input");
{
  const result = parseCSV("");
  assertEqual(result.rows.length, 0, "empty input: no rows");
  assertEqual(result.headers.length, 0, "empty input: no headers");
  assertEqual(result.errors.length, 0, "empty input: no errors");
}
{
  const result = parseCSV("   \n  \n ");
  assertEqual(result.rows.length, 0, "whitespace-only input: no rows");
}

section("Edge case: header only (no data rows)");
{
  const csv = `name,age,city`;
  const result = parseCSV(csv);
  assertEqual(result.headers, ["name", "age", "city"], "header-only: headers parsed");
  assertEqual(result.rows.length, 0, "header-only: no rows");
  assertEqual(result.count(), 0, "header-only: count 0");
  assertEqual(result.sum("age"), 0, "header-only: sum 0");
  assertEqual(result.average("age"), 0, "header-only: average 0");
}

section("Edge case: single column");
{
  const csv = `value\n10\n20\n30`;
  const result = parseCSV(csv);
  assertEqual(result.headers, ["value"], "single column: one header");
  assertEqual(result.rows.length, 3, "single column: 3 rows");
  assertEqual(result.sum("value"), 60, "single column: sum");
}

section("Edge case: single row");
{
  const csv = `x,y\n1,2`;
  const result = parseCSV(csv);
  assertEqual(result.rows.length, 1, "single row: 1 row");
  assertEqual(result.rows[0]["x"], 1, "single row: x value");
  assertEqual(result.rows[0]["y"], 2, "single row: y value");
}

section("Edge case: very large fields");
{
  const bigValue = "x".repeat(100_000);
  const csv = `data\n"${bigValue}"`;
  const result = parseCSV(csv);
  assertEqual(result.rows.length, 1, "large field: 1 row");
  assertEqual((result.rows[0]["data"] as string).length, 100_000, "large field: 100k chars");
}

section("Edge case: quoted field spanning multiple lines");
{
  const csv = `name,bio\nAlice,"Line 1\nLine 2\nLine 3"\nBob,"Simple"`;
  const result = parseCSV(csv);
  assertEqual(result.rows.length, 2, "multiline field: 2 rows");
  assertEqual(result.rows[0]["bio"], "Line 1\nLine 2\nLine 3", "multiline field: newlines preserved");
  assertEqual(result.rows[1]["name"], "Bob", "multiline field: next row correct");
}

section("Edge case: CRLF line endings");
{
  const csv = "name,age\r\nAlice,30\r\nBob,25";
  const result = parseCSV(csv, { lineSeparator: "\r\n" });
  assertEqual(result.rows.length, 2, "CRLF: 2 rows");
  assertEqual(result.rows[0]["name"], "Alice", "CRLF: first name");
}

section("Edge case: numbers that shouldn't coerce");
{
  const csv = `val\n12abc\n1.2.3\n+5\n1e3\n 42 `;
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], "12abc", "12abc stays string");
  assertEqual(result.rows[1]["val"], "1.2.3", "1.2.3 stays string");
  assertEqual(result.rows[2]["val"], "+5", "+5 stays string");
  assertEqual(result.rows[3]["val"], "1e3", "1e3 stays string");
  assertEqual(result.rows[4]["val"], " 42 ", "padded number stays string");
}

section("Edge case: negative float");
{
  const csv = `val\n-3.14`;
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], -3.14, "-3.14 coerced to float");
}

section("Combination: filter + aggregation");
{
  const csv = `product,category,price
Widget,A,10
Gadget,B,20
Gizmo,A,30
Thingo,B,40
Doodad,A,50`;
  const result = parseCSV(csv);
  const catA = result.filter((r) => r["category"] === "A");
  assertEqual(catA.length, 3, "filter category A: 3 items");
  // manual sum on filtered
  const sumA = catA.reduce((s, r) => s + (r["price"] as number), 0);
  assertEqual(sumA, 90, "sum of category A prices");
}

// ─── Report ──────────────────────────────────────────────────────────────────

console.log(`\n${"═".repeat(50)}`);
console.log(`Results: ${passed} passed, ${failed} failed`);
if (failures.length > 0) {
  console.log(`\nFailures:`);
  failures.forEach((f, i) => console.log(`  ${i + 1}. ${f}`));
  process.exit(1);
} else {
  console.log("All tests passed! ✅");
}

